// 1. Define a strategy interface for history management.
//    (This could live in a new file, e.g., 'history/historyManager.ts')
export interface IHistoryManager {
  add(content: Content): void;
  set(history: Content[]): void;
  get(): Content[];
  clear(): void;
}

// 2. Create a concrete implementation of the strategy.
//    (This could live in a new file, e.g., 'history/truncatingHistory.ts')
export class TruncatingHistoryManager implements IHistoryManager {
  private history: Content[] = [];
  private readonly maxLength: number;

  constructor(maxLength: number = 10) { // Make max length configurable
    this.maxLength = maxLength;
  }

  add(content: Content): void {
    this.history.push(content);
    if (this.history.length > this.maxLength) {
      // Correctly and safely truncate the history from the beginning.
      this.history.splice(0, this.history.length - this.maxLength);
    }
  }

  set(history: Content[]): void {
    this.history = [...history]; // Use a copy for safety
    if (this.history.length > this.maxLength) {
      this.history.splice(0, this.history.length - this.maxLength);
    }
  }

  get(): Content[] {
    return this.history;
  }

  clear(): void {
    this.history = [];
  }
}

