export class HybridTokenStorage extends BaseTokenStorage {
  private credentialsCache: OAuthCredentials | null = null;

  async getCredentials(serverName: string): Promise<OAuthCredentials | null> {
    // First, check the safe, instance-level cache.
    if (this.credentialsCache && this.credentialsCache.serverName === serverName) {
      return this.credentialsCache;
    }

    // If not cached, fall back to the underlying persistent storage.
    const storage = await this.getStorage();
    const credentials = await storage.getCredentials(serverName);

    // Populate the cache for subsequent calls.
    if (credentials) {
      this.credentialsCache = credentials;
    }

    return credentials;
  }

  async setCredentials(credentials: OAuthCredentials): Promise<void> {
    // Update both the instance cache and persistent storage.
    this.credentialsCache = credentials;
    const storage = await this.getStorage();
    await storage.setCredentials(credentials);
  }

  async clearCredentials(serverName: string): Promise<void> {
    // Ensure the cache is cleared along with the persistent storage.
    this.credentialsCache = null;
    const storage = await this.getStorage();
    await storage.clearCredentials(serverName);
  }
}
