```javascript
/**
 * @fileoverview Disallows unstructured object spreading in favor of Object.assign for explicit type safety.
 */
'use strict';

module.exports = {
  meta: {
    type: 'suggestion',
    docs: {
      description:
        'Disallow unstructured object spreading to enforce explicit type mappings with Object.assign.',
      category: 'Best Practices',
      recommended: false,
    },
    fixable: 'code',
    schema: [], // no options
    messages: {
      useObjectAssign:
        'Avoid unstructured spreading. Use Object.assign({}, {{spreadVar}}) to ensure explicit type mappings.',
    },
  },

  create(context) {
    const sourceCode = context.getSourceCode();

    return {
      SpreadElement(node) {
        // We are only targeting spreads in ObjectExpressions, e.g. `{ ...foo }`
        if (node.parent.type !== 'ObjectExpression') {
          return;
        }

        // This rule is designed to replace spreads that are the *only* property
        // in an object, like `const newObj = { ...oldObj };`
        // The original regex had this limitation, so we will honor it to prevent
        // breaking changes for more complex objects like `{ a: 1, ...b }`.
        if (node.parent.properties.length !== 1) {
          return;
        }

        const spreadVar = sourceCode.getText(node.argument);

        context.report({
          node: node,
          messageId: 'useObjectAssign',
          data: {
            spreadVar: spreadVar,
          },
          fix(fixer) {
            return fixer.replaceText(
              node.parent,
              `Object.assign({}, ${spreadVar})`
            );
          },
        });
      },
    };
  },
};
