#!/usr/bin/env node
const fs = require('fs');
const glob = require('glob');
const recast = require('recast');

// This script safely transforms `{ ...foo }` into `Object.assign({}, foo)`
// using an Abstract Syntax Tree (AST) parser, avoiding the dangers of regex.
//
// To run this, you will need to add `recast` to your dev dependencies:
// npm install --save-dev recast

glob('packages/**/*.ts', { nodir: true }, (err, files) => {
  if (err) {
    console.error('Error finding files:', err);
    process.exit(1);
  }

  files.forEach(file => {
    try {
      const originalCode = fs.readFileSync(file, 'utf8');
      const ast = recast.parse(originalCode, {
        // Use the TypeScript parser to handle TS-specific syntax
        parser: require('recast/parsers/typescript'),
      });

      let changesMade = false;

      recast.visit(ast, {
        visitObjectExpression(path) {
          // This transform targets only object literals that contain *exclusively* a single spread element.
          // Example: `const a = { ...b };`
          // It will NOT transform: `const a = { c: 1, ...b };`
          if (
            path.node.properties.length === 1 &&
            path.node.properties[0].type === 'SpreadElement'
          ) {
            changesMade = true;
            const spreadElement = path.node.properties[0];

            // Build the `Object.assign({}, identifier)` AST node
            const objectAssignCall = recast.types.builders.callExpression(
              recast.types.builders.memberExpression(
                recast.types.builders.identifier('Object'),
                recast.types.builders.identifier('assign')
              ),
              [
                recast.types.builders.objectExpression([]), // The empty object {}
                spreadElement.argument, // The identifier being spread
              ]
            );

            // Replace the original `{ ...foo }` node with the new call expression
            path.replace(objectAssignCall);
          }

          // Allow traversal to continue into nested structures
          this.traverse(path);
          return false; // We've handled the replacement, so prevent default traversal of this node's children.
        },
      });

      if (changesMade) {
        const { code: updatedCode } = recast.print(ast, {
          tabWidth: 2,
          quote: 'single',
        });
        fs.writeFileSync(file, updatedCode, 'utf8');
        console.log(`Updated: ${file}`);
      }
    } catch (parseError) {
      console.error(`Could not process file ${file} due to parsing error:`, parseError);
    }
  });
});
