#!/usr/bin/env node

// This script safely transforms `{ ...foo }` into `Object.assign({}, foo)`
// using an Abstract Syntax Tree (AST) parser. This is the correct and robust
// way to perform code modifications, unlike fragile regular expressions.
//
// To run this script, you'll need to install its dependencies:
// npm install recast glob --save-dev
//
// Then, you can run `npm run lint:fix-spread`.

const fs = require('fs').promises;
const { glob } = require('glob');
const recast = require('recast');

async function run() {
  // Use the modern promise-based API for glob for cleaner async/await syntax.
  const files = await glob('packages/**/*.ts', { ignore: 'node_modules/**' });

  // Process files in parallel for better performance.
  const tasks = files.map(async (file) => {
    // Use asynchronous file I/O to avoid blocking the Node.js event loop.
    const originalCode = await fs.readFile(file, 'utf8');
    let ast;

    try {
      // Parse the source code into an AST. We must specify the TypeScript parser.
      ast = recast.parse(originalCode, {
        parser: require('recast/parsers/typescript'),
      });
    } catch (error) {
      console.error(`Failed to parse ${file}: ${error.message}`);
      return; // Skip files that can't be parsed
    }

    // `recast.visit` traverses the AST, allowing us to find and modify specific nodes.
    recast.visit(ast, {
      // We are looking for ObjectExpression nodes in the code.
      visitObjectExpression(path) {
        const { node } = path;

        // The target pattern is an object literal containing ONLY a spread element, like `{ ...foo }`.
        if (node.properties.length === 1 && node.properties[0].type === 'SpreadElement') {
          const spreadElement = node.properties[0];

          // Create the replacement node: `Object.assign({}, spreadElement.argument)`
          const newCallExpression = recast.types.builders.callExpression(
            recast.types.builders.memberExpression(
              recast.types.builders.identifier('Object'),
              recast.types.builders.identifier('assign')
            ),
            [
              recast.types.builders.objectExpression([]),
              spreadElement.argument,
            ]
          );

          // Replace the original `{ ...foo }` node with the new `Object.assign(...)` node.
          path.replace(newCallExpression);
        }

        // It's important to continue traversing down the tree.
        this.traverse(path);
      },
    });

    // `recast.print` converts the modified AST back into code, preserving formatting.
    const transformedCode = recast.print(ast, { tabWidth: 2, quote: 'single' }).code;

    // Only write the file back if changes were actually made.
    if (originalCode !== transformedCode) {
      console.log(`Updating spread operator in ${file}`);
      await fs.writeFile(file, transformedCode, 'utf8');
    }
  });

  await Promise.all(tasks);
  console.log('Spread operator fix script finished.');
}

run().catch((error) => {
  console.error('An error occurred while fixing spread operators:', error);
  process.exit(1);
});
