#!/usr/bin/env node
const fs = require('fs');
const glob = require('glob');
const recast = require('recast');

/**
 * This script safely transforms standalone object spreads (`{ ...foo }`) into 
 * `Object.assign({}, foo)` using an Abstract Syntax Tree (AST). This avoids
 * the pitfalls of regex-based replacement, which can corrupt valid code like
 * object destructuring.
 * 
 * To run this script, you will need to add `recast` and its dependencies:
 * `npm install --save-dev recast @babel/parser @babel/traverse`
 */
glob('packages/**/*.ts', { ignore: 'node_modules/**' }, (err, files) => {
  if (err) {
    console.error("Error finding files:", err);
    process.exit(1);
  }

  files.forEach(file => {
    const originalContent = fs.readFileSync(file, 'utf8');
    let ast;

    try {
      // Parse the code into an AST using recast, which preserves formatting.
      ast = recast.parse(originalContent, {
        parser: require('recast/parsers/babel'),
      });
    } catch (parseError) {
      console.error(`Failed to parse ${file}:`, parseError);
      return; // Skip files with syntax errors
    }

    // Use recast's visit method to traverse and transform the AST.
    recast.visit(ast, {
      visitObjectExpression(path) {
        const { node } = path;

        // Target condition: An ObjectExpression with exactly one property,
        // which must be a SpreadElement. This is the signature for `{ ...foo }`.
        if (node.properties.length === 1 && node.properties[0].type === 'SpreadElement') {
          const spreadElement = node.properties[0];

          // Use recast's AST builder to create `Object.assign({}, foo)`
          const newExpression = recast.types.builders.callExpression(
            recast.types.builders.memberExpression(
              recast.types.builders.identifier('Object'),
              recast.types.builders.identifier('assign')
            ),
            [
              recast.types.builders.objectExpression([]), // {}
              spreadElement.argument                      // foo from `...foo`
            ]
          );

          // Replace the original `{ ...foo }` node with the new `Object.assign` call.
          path.replace(newExpression);

          // We've transformed this node, so we don't need to traverse its children.
          return false;
        }

        // For all other ObjectExpressions, continue traversing their children.
        this.traverse(path);
      }
    });

    // Generate the modified code from the AST, preserving original formatting.
    const newContent = recast.print(ast, { tabWidth: 2, quote: 'single' }).code;

    // Only write to the file system if changes were actually made.
    if (originalContent !== newContent) {
      fs.writeFileSync(file, newContent, 'utf8');
      console.log(`Refactored spreads in: ${file}`);
    }
  });
});
