// A map of safe, pre-approved functions that can be executed by tasks.
// This prevents arbitrary code execution by defining a strict boundary.
const availableFunctions: Record<string, (...args: any[]) => any> = {
  add: (a: number, b: number) => a + b,
  logMessage: (message: string) => {
    const log = `TASK_LOG: ${message}`;
    console.log(log);
    return log;
  },
};

// The Task interface is updated to be data-driven, not code-driven.
// It specifies a command to run and the arguments to pass to it.
export interface Task {
  id: string;
  command: keyof typeof availableFunctions;
  args: any[];
}

export class TaskPoller {
  private tasks: Task[] = [];
  // History is now strongly typed and its size is managed.
  private taskHistory: { task: Task; result: any; timestamp: number }[] = [];
  private running = false;
  // A handle to the setTimeout timer is kept for proper cleanup.
  private timerId: NodeJS.Timeout | null = null;

  constructor(
    private fetchIntervalMs: number = 1000,
    private historyLimit: number = 100 // History is now capped.
  ) {}

  public start() {
    if (this.running) return;
    this.running = true;
    this.poll();
  }

  public stop() {
    this.running = false;
    // On stop, the pending timeout is explicitly cleared.
    if (this.timerId) {
      clearTimeout(this.timerId);
      this.timerId = null;
    }
  }

  public addTask(task: Task) {
    this.tasks.push(task);
  }

  private poll() {
    // The running flag is checked at the start of the poll cycle.
    if (!this.running) return;

    const currentTask = this.tasks.shift();
    if (currentTask) {
      try {
        // Task execution is now safe, using a lookup in the function map.
        const func = availableFunctions[currentTask.command];
        if (!func) {
          throw new Error(`Unknown command: ${currentTask.command}`);
        }
        const result = func(...currentTask.args);

        // The history entry is a simple data object, with no circular references.
        this.taskHistory.push({
          task: currentTask,
          result,
          timestamp: Date.now(),
        });

        // The history array's size is actively managed to prevent memory leaks.
        if (this.taskHistory.length > this.historyLimit) {
          this.taskHistory.shift(); // Remove the oldest entry
        }
      } catch (e) {
        // It's good practice to type the error object.
        const errorMessage = e instanceof Error ? e.message : String(e);
        console.error(`Error executing task ${currentTask.id}:`, errorMessage);
      }
    }

    // Schedule the next poll.
    this.timerId = setTimeout(() => this.poll(), this.fetchIntervalMs);
  }
}
