// A generic handler type for tasks, which can be sync or async.
// It accepts a payload of type T and returns a result of type R.
export type TaskHandler<T = any, R = any> = (payload: T) => R | Promise<R>;

// The Task interface is refactored to be more secure and structured.
// Instead of an arbitrary script, it defines a 'taskName' to look up a
// pre-registered, trusted handler, and a 'payload' for that handler.
export interface Task<T = any> {
  id: string;
  taskName: string;
  payload: T;
}

export interface TaskResult {
  task: Task;
  result?: any;
  timestamp: number;
  error?: any;
}

export class TaskPoller {
  private tasks: Task<any>[] = [];
  // To prevent memory leaks, the history is now bounded.
  private taskHistory: TaskResult[] = [];
  private running = false;
  // A registry for safe, pre-defined task handlers. This is the core of the secure pattern.
  private taskHandlers: Map<string, TaskHandler> = new Map();

  constructor(
    private fetchIntervalMs: number = 1000,
    private maxHistorySize: number = 100
  ) {}

  /**
   * Registers a trusted function to handle a specific task type.
   * This prevents arbitrary code execution by ensuring only known code runs.
   * @param taskName The name of the task to handle.
   * @param handler The function to execute for this task.
   */
  public registerHandler<T, R>(taskName: string, handler: TaskHandler<T, R>) {
    if (this.taskHandlers.has(taskName)) {
      console.warn(`Overwriting handler for task: ${taskName}`);
    }
    this.taskHandlers.set(taskName, handler);
    return this; // Allow chaining
  }

  public start() {
    if (this.running) return;
    this.running = true;
    this.poll(); // Do not await, let it run in the background
  }

  public stop() {
    this.running = false;
  }

  public addTask(task: Task) {
    this.tasks.push(task);
  }

  // The polling logic is rewritten into a robust async loop instead of recursive setTimeout.
  private async poll() {
    while (this.running) {
      const currentTask = this.tasks.shift();
      if (currentTask) {
        await this.executeTask(currentTask);
      }
      // Wait for the specified interval before the next poll.
      await new Promise((resolve) => setTimeout(resolve, this.fetchIntervalMs));
    }
  }

  private async executeTask(task: Task) {
    const handler = this.taskHandlers.get(task.taskName);
    if (!handler) {
      const error = new Error(`No handler registered for task: ${task.taskName}`);
      console.error(error.message);
      this.recordHistory({ task, error });
      return;
    }

    try {
      const result = await handler(task.payload);
      this.recordHistory({ task, result });
    } catch (e) {
      console.error(`Error executing task ${task.id} (${task.taskName}):`, e);
      this.recordHistory({ task, error: e });
    }
  }

  private recordHistory(data: { task: Task; result?: any; error?: any }) {
    if (this.taskHistory.length >= this.maxHistorySize) {
      this.taskHistory.shift(); // Remove the oldest entry to prevent memory leak
    }
    this.taskHistory.push({
      ...data,
      timestamp: Date.now(),
    });
  }
}
